enum MenuBarStatusItemIconSource: Equatable {
    case systemSymbol(String)
    case svgTemplate(
        name: String,
        viewBox: String,
        path: String,
        fallbackSystemSymbol: String
    )

    var fallbackSystemSymbolName: String {
        switch self {
        case .systemSymbol(let name):
            return name
        case .svgTemplate(_, _, _, let fallbackSystemSymbol):
            return fallbackSystemSymbol
        }
    }

    func makeTemplateImage(accessibilityDescription: String) -> NSImage? {
        switch self {
        case .systemSymbol(let name):
            return Self.systemSymbolImage(name: name, accessibilityDescription: accessibilityDescription)
        case .svgTemplate(_, let viewBox, let path, let fallbackSystemSymbol):
            let svg = """
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="\(viewBox)" fill="black" fill-rule="evenodd">
              <g transform="translate(2 2) scale(0.8333333333)">
                <path d="\(path)"/>
              </g>
            </svg>
            """
            guard let data = svg.data(using: .utf8),
                  let image = NSImage(data: data) else {
                return Self.systemSymbolImage(name: fallbackSystemSymbol, accessibilityDescription: accessibilityDescription)
            }
            image.isTemplate = true
            image.accessibilityDescription = accessibilityDescription
            return image
        }
    }

    private static func systemSymbolImage(name: String, accessibilityDescription: String) -> NSImage? {
        let image = NSImage(systemSymbolName: name, accessibilityDescription: accessibilityDescription)
        image?.isTemplate = true
        return image
    }
}

